import React, { useState } from 'react'
import axios from 'axios'
import { useNavigate } from 'react-router-dom'
import styled from 'styled-components'


const StyledForm = styled.form`
    display: flex;
    flex-direction: column;
    min-width: 250px;
    max-width: 50vw;
    align-items: baseline;
    div input {
        margin-right: 25px;
    }
`

const NewPost = ({ addPost }) => { 
    const initialState = {
        status_body: '',
        date: '',
        file: ''
    }
    const navigate = useNavigate()

    const [formData, setFormData] = useState(initialState)


    const handleChange = (e) => {
        console.log(e.target)
        setFormData({...formData, [e.target.id] : e.target.value})
    }

    const handleSubmit = (e) => {
        e.preventDefault()
        console.log(formData)
        axios.post('http://localhost:8000/bunnybook/posts', formData )
        .then(res =>  {
            setFormData(initialState)
            addPost(res.data)
            navigate('/', { replace: true })
        })

    }


  return (
    <StyledForm onSubmit={handleSubmit}>
        <h1> Create new Item</h1>
            <div>
                <label htmlFor='status_body'>Post</label>
                <input id='status_body' name='status_body' type='text' onChange={handleChange} />
            </div>
            <div>
                <label htmlFor='date'>Date</label>
                <input id='date' name='date' type='text'   onChange={handleChange} />
            </div>
            <div>
                <label htmlFor='file'>File</label>
                <input id='file' name='file' type='text'   onChange={handleChange} />
            </div>


            <input type='submit' value='+ Post' />
    </StyledForm>
  )
}

export default NewPost
